export type Category =
  | "Medio ambiente"
  | "Educación"
  | "Salud"
  | "Comunidad"
  | "Océanos"
  | "Alimentación"
  | "Tecnología";

// Payment/financial information for project donations
export type PaymentInfo = {
  iban?: string;               // International Bank Account Number
  paypal?: string;             // PayPal email or payment link
  stripeAccountId?: string;    // Stripe connected account ID
  btcAddress?: string;         // Bitcoin wallet address
  donationUrl?: string;        // Custom donation page URL
  acceptsDonations?: boolean;  // Whether project accepts donations
};

export type Project = {
  id: string;
  name: string;
  name_en?: string;
  name_de?: string;
  description?: string;
  description_en?: string;
  description_de?: string;
  image_url?: string;
  info_url?: string;
  category: Category;
  lat: number;
  lng: number;
  city: string;
  country: string;
  spots?: number;
  volunteers?: number;
  address?: string;
  // Optional scheduling for event filtering
  startsAt?: string;
  endsAt?: string;
  isPermanent?: boolean;
  tags?: string[];
  // Payment/financial information
  paymentInfo?: PaymentInfo;
};

